import { useState, useRef, useCallback } from "react";

const CHUNK_SIZE = 5 * 1024 * 1024; // 5 MB

interface UploadProgress {
  phase: "idle" | "uploading" | "finalizing" | "done" | "error";
  percent: number;
  uploadedChunks: number;
  totalChunks: number;
  videoId: number | null;
  error: string | null;
}

export function useChunkedUpload() {
  const [progress, setProgress] = useState<UploadProgress>({
    phase: "idle", percent: 0, uploadedChunks: 0,
    totalChunks: 0, videoId: null, error: null,
  });
  const abortRef = useRef(false);

  const upload = useCallback(async (file: File, title: string) => {
    abortRef.current = false;
    const totalChunks = Math.ceil(file.size / CHUNK_SIZE);

    setProgress({ phase: "uploading", percent: 0, uploadedChunks: 0,
      totalChunks, videoId: null, error: null });

    // 1. Init upload session
    const initRes = await fetch("/api/upload/init", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        filename: file.name,
        fileSize: file.size,
        totalChunks,
        title,
      }),
    });
    if (!initRes.ok) {
      const err = await initRes.json();
      setProgress(p => ({ ...p, phase: "error", error: err.error }));
      return;
    }
    const { uploadId, videoId } = await initRes.json();

    // 2. Upload chunks sequentially
    for (let i = 0; i < totalChunks; i++) {
      if (abortRef.current) {
        setProgress(p => ({ ...p, phase: "error", error: "Cancelled" }));
        return;
      }
      const start = i * CHUNK_SIZE;
      const end = Math.min(start + CHUNK_SIZE, file.size);
      const chunk = file.slice(start, end);

      const form = new FormData();
      form.append("chunkIndex", String(i));
      form.append("chunk", chunk);

      const res = await fetch(`/api/upload/${uploadId}/chunk`, {
        method: "POST",
        body: form,
      });
      if (!res.ok) {
        setProgress(p => ({ ...p, phase: "error", error: "Chunk upload failed" }));
        return;
      }
      setProgress(p => ({
        ...p,
        uploadedChunks: i + 1,
        percent: Math.round(((i + 1) / totalChunks) * 100),
      }));
    }

    // 3. Finalize
    setProgress(p => ({ ...p, phase: "finalizing" }));
    const completeRes = await fetch(`/api/upload/${uploadId}/complete`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ videoId, totalChunks }),
    });
    if (!completeRes.ok) {
      setProgress(p => ({ ...p, phase: "error", error: "Finalization failed" }));
      return;
    }
    setProgress(p => ({ ...p, phase: "done", percent: 100, videoId }));
  }, []);

  const cancel = useCallback(() => { abortRef.current = true; }, []);

  return { progress, upload, cancel };
}

import os
from flask import Blueprint, send_file, abort

streaming_bp = Blueprint("streaming", __name__)

HLS_DIR = os.environ.get("HLS_OUTPUT_DIR", "/data/hls")


@streaming_bp.route("/hls/<int:video_id>/<path:filename>")
def serve_hls(video_id, filename):
    """Serve HLS manifests and segments with correct MIME types."""
    file_path = os.path.join(HLS_DIR, str(video_id), filename)
    if not os.path.isfile(file_path):
        abort(404)

    if filename.endswith(".m3u8"):
        mimetype = "application/vnd.apple.mpegurl"
    elif filename.endswith(".ts"):
        mimetype = "video/mp2t"
    else:
        mimetype = "application/octet-stream"

    response = send_file(file_path, mimetype=mimetype)
    response.headers["Access-Control-Allow-Origin"] = "*"
    response.headers["Cache-Control"] = "public, max-age=31536000"
    return response

import React, { useRef, useEffect, useState, useCallback } from "react";
import Hls from "hls.js";

interface VideoPlayerProps {
  src: string; // HLS master playlist URL
  poster?: string;
  autoPlay?: boolean;
  onTimeUpdate?: (currentTime: number, duration: number) => void;
}

export default function VideoPlayer({ src, poster, autoPlay, onTimeUpdate }: VideoPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const hlsRef = useRef<Hls | null>(null);
  const [playing, setPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [quality, setQuality] = useState(-1); // -1 = auto
  const [levels, setLevels] = useState<{ height: number; index: number }[]>([]);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    if (Hls.isSupported()) {
      const hls = new Hls({
        enableWorker: true,
        lowLatencyMode: false,
        startLevel: -1, // auto
      });
      hls.loadSource(src);
      hls.attachMedia(video);

      hls.on(Hls.Events.MANIFEST_PARSED, (_event, data) => {
        setLevels(
          data.levels.map((lvl, i) => ({ height: lvl.height, index: i }))
        );
        if (autoPlay) video.play();
      });

      hlsRef.current = hls;
      return () => { hls.destroy(); };
    } else if (video.canPlayType("application/vnd.apple.mpegurl")) {
      // Safari native HLS
      video.src = src;
      if (autoPlay) video.play();
    }
  }, [src, autoPlay]);

  const handleTimeUpdate = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    setCurrentTime(video.currentTime);
    setDuration(video.duration || 0);
    onTimeUpdate?.(video.currentTime, video.duration);
  }, [onTimeUpdate]);

  const togglePlay = () => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) { video.play(); setPlaying(true); }
    else { video.pause(); setPlaying(false); }
  };

  const seek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (videoRef.current) videoRef.current.currentTime = time;
    setCurrentTime(time);
  };

  const changeVolume = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = parseFloat(e.target.value);
    if (videoRef.current) videoRef.current.volume = v;
    setVolume(v);
  };

  const changeQuality = (levelIndex: number) => {
    if (hlsRef.current) {
      hlsRef.current.currentLevel = levelIndex; // -1 for auto
    }
    setQuality(levelIndex);
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;
    if (!document.fullscreenElement) {
      containerRef.current.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  const formatTime = (sec: number) => {
    const m = Math.floor(sec / 60);
    const s = Math.floor(sec % 60);
    return `${m}:${s.toString().padStart(2, "0")}`;
  };

  return (
    <div ref={containerRef} className="video-player">
      <video
        ref={videoRef}
        poster={poster}
        onTimeUpdate={handleTimeUpdate}
        onPlay={() => setPlaying(true)}
        onPause={() => setPlaying(false)}
        onClick={togglePlay}
        style={{ width: "100%", display: "block", background: "#000" }}
      />
      <div className="controls">
        <button onClick={togglePlay}>{playing ? "Pause" : "Play"}</button>
        <span>{formatTime(currentTime)}</span>
        <input
          type="range" min={0} max={duration || 0} step={0.1}
          value={currentTime} onChange={seek}
          style={{ flex: 1 }}
        />
        <span>{formatTime(duration)}</span>
        <input
          type="range" min={0} max={1} step={0.05}
          value={volume} onChange={changeVolume}
          style={{ width: 80 }}
        />
        <select
          value={quality}
          onChange={(e) => changeQuality(parseInt(e.target.value))}
        >
          <option value={-1}>Auto</option>
          {levels.map((l) => (
            <option key={l.index} value={l.index}>{l.height}p</option>
          ))}
        </select>
        <button onClick={toggleFullscreen}>
          {isFullscreen ? "Exit FS" : "Fullscreen"}
        </button>
      </div>
    </div>
  );
}

import React, { useRef, useEffect } from "react";
import videojs from "video.js";
import Player from "video.js/dist/types/player";
import "video.js/dist/video-js.css";

interface VideoJsPlayerProps {
  src: string;
  poster?: string;
  onReady?: (player: Player) => void;
}

export default function VideoJsPlayer({ src, poster, onReady }: VideoJsPlayerProps) {
  const videoRef = useRef<HTMLDivElement>(null);
  const playerRef = useRef<Player | null>(null);

  useEffect(() => {
    if (!videoRef.current) return;

    const videoElement = document.createElement("video-js");
    videoElement.classList.add("vjs-big-play-centered");
    videoRef.current.appendChild(videoElement);

    const player = videojs(videoElement, {
      autoplay: false,
      controls: true,
      responsive: true,
      fluid: true,
      poster,
      sources: [{ src, type: "application/x-mpegURL" }],
      html5: {
        vhs: {
          overrideNative: true,
          enableLowInitialPlaylist: true,
        },
      },
    });

    player.qualityLevels();
    playerRef.current = player;
    onReady?.(player);

    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, [src, poster, onReady]);

  return <div ref={videoRef} data-vjs-player />;
}

import React, { useState, useEffect } from "react";

interface Comment {
  id: number;
  body: string;
  like_count: number;
  created_at: string;
  display_name: string;
  avatar_url: string | null;
  replies?: Comment[];
}

interface Props {
  videoId: number;
}

export default function CommentSection({ videoId }: Props) {
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState("");
  const [replyTo, setReplyTo] = useState<number | null>(null);
  const [replyText, setReplyText] = useState("");
  const [sort, setSort] = useState<"newest" | "top">("newest");

  useEffect(() => {
    fetch(`/api/videos/${videoId}/comments?sort=${sort}`)
      .then((r) => r.json())
      .then((data) => setComments(data.comments));
  }, [videoId, sort]);

  const submitComment = async (parentId?: number) => {
    const body = parentId ? replyText : newComment;
    if (!body.trim()) return;

    const res = await fetch(`/api/videos/${videoId}/comments`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ body, parentId }),
    });
    if (res.ok) {
      setNewComment("");
      setReplyText("");
      setReplyTo(null);
      // Refresh comments
      const data = await fetch(`/api/videos/${videoId}/comments?sort=${sort}`).then(r => r.json());
      setComments(data.comments);
    }
  };

  const likeComment = async (commentId: number) => {
    await fetch(`/api/comments/${commentId}/like`, { method: "POST" });
  };

  const timeAgo = (dateStr: string) => {
    const diff = Date.now() - new Date(dateStr).getTime();
    const hours = Math.floor(diff / 3600000);
    if (hours < 1) return "just now";
    if (hours < 24) return `${hours}h ago`;
    const days = Math.floor(hours / 24);
    if (days < 30) return `${days}d ago`;
    return `${Math.floor(days / 30)}mo ago`;
  };

  return (
    <div className="comment-section">
      <div className="comment-header">
        <h3>{comments.length} Comments</h3>
        <select value={sort} onChange={(e) => setSort(e.target.value as "newest" | "top")}>
          <option value="newest">Newest</option>
          <option value="top">Top</option>
        </select>
      </div>

      <div className="comment-form">
        <textarea
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          placeholder="Add a comment..."
          maxLength={2000}
        />
        <button onClick={() => submitComment()} disabled={!newComment.trim()}>
          Comment
        </button>
      </div>

      {comments.map((c) => (
        <div key={c.id} className="comment">
          <div className="comment-meta">
            <strong>{c.display_name}</strong>
            <span>{timeAgo(c.created_at)}</span>
          </div>
          <p>{c.body}</p>
          <div className="comment-actions">
            <button onClick={() => likeComment(c.id)}>Like ({c.like_count})</button>
            <button onClick={() => setReplyTo(replyTo === c.id ? null : c.id)}>Reply</button>
          </div>

          {replyTo === c.id && (
            <div className="reply-form">
              <textarea
                value={replyText}
                onChange={(e) => setReplyText(e.target.value)}
                placeholder="Write a reply..."
                maxLength={2000}
              />
              <button onClick={() => submitComment(c.id)}>Reply</button>
            </div>
          )}

          {c.replies?.map((r) => (
            <div key={r.id} className="comment reply">
              <div className="comment-meta">
                <strong>{r.display_name}</strong>
                <span>{timeAgo(r.created_at)}</span>
              </div>
              <p>{r.body}</p>
              <button onClick={() => likeComment(r.id)}>Like ({r.like_count})</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

@analytics_bp.route("/retention/<int:video_id>", methods=["GET"])
@login_required
def video_retention(video_id):
    """Return retention data as percentage of viewers at each 10s bucket."""
    db = get_db()
    cur = db.cursor()

    cur.execute("SELECT duration_seconds FROM videos WHERE id = %s", (video_id,))
    row = cur.fetchone()
    if not row:
        return jsonify(error="Video not found"), 404
    duration = row[0] or 0

    cur.execute("""
        SELECT COUNT(*) FROM watch_history WHERE video_id = %s
    """, (video_id,))
    total_views = cur.fetchone()[0]
    if total_views == 0:
        return jsonify(retention=[], totalViews=0)

    bucket_size = 10
    buckets = []
    for t in range(0, duration, bucket_size):
        cur.execute("""
            SELECT COUNT(*) FROM watch_history
            WHERE video_id = %s AND watch_seconds >= %s
        """, (video_id, t))
        count = cur.fetchone()[0]
        buckets.append({
            "timestamp": t,
            "percentage": round(count / total_views * 100, 1)
        })

    return jsonify(retention=buckets, totalViews=total_views)

import os
import boto3
from botocore.config import Config

s3 = boto3.client("s3", config=Config(signature_version="s3v4"))
BUCKET = os.environ.get("S3_BUCKET", "my-video-platform-hls")


def upload_hls_to_s3(video_id: int, local_dir: str) -> str:
    """Upload all HLS files for a video to S3.

    Returns the S3 URL for the master playlist.
    """
    prefix = f"hls/{video_id}"

    for root, _dirs, files in os.walk(local_dir):
        for fname in files:
            local_path = os.path.join(root, fname)
            relative = os.path.relpath(local_path, local_dir)
            s3_key = f"{prefix}/{relative}"

            content_type = "application/vnd.apple.mpegurl"
            if fname.endswith(".ts"):
                content_type = "video/mp2t"

            s3.upload_file(
                local_path, BUCKET, s3_key,
                ExtraArgs={
                    "ContentType": content_type,
                    "CacheControl": "public, max-age=31536000",
                }
            )

    return f"https://{BUCKET}.s3.amazonaws.com/{prefix}/master.m3u8"


def generate_presigned_upload_url(key: str, content_type: str, expires: int = 3600) -> str:
    """Generate a presigned URL for direct client-to-S3 uploads."""
    return s3.generate_presigned_url(
        "put_object",
        Params={"Bucket": BUCKET, "Key": key, "ContentType": content_type},
        ExpiresIn=expires
    )

import React, { useState, useEffect, useRef, useCallback } from "react";

interface VideoCard {
  id: number;
  title: string;
  slug: string;
  thumbnail_url: string;
  duration_seconds: number;
  view_count: number;
  channel_name: string;
  published_at: string;
}

export default function InfiniteVideoFeed({ endpoint }: { endpoint: string }) {
  const [videos, setVideos] = useState<VideoCard[]>([]);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [loading, setLoading] = useState(false);
  const observerRef = useRef<HTMLDivElement>(null);

  const fetchPage = useCallback(async (p: number) => {
    setLoading(true);
    const res = await fetch(`${endpoint}?page=${p}`);
    const data = await res.json();
    const newVideos: VideoCard[] = data.videos ?? data.results ?? [];
    setVideos((prev) => [...prev, ...newVideos]);
    setHasMore(newVideos.length === 20);
    setLoading(false);
  }, [endpoint]);

  useEffect(() => { fetchPage(1); }, [fetchPage]);

  useEffect(() => {
    if (!observerRef.current || !hasMore) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !loading) {
          setPage((p) => {
            const next = p + 1;
            fetchPage(next);
            return next;
          });
        }
      },
      { threshold: 0.1 }
    );
    observer.observe(observerRef.current);
    return () => observer.disconnect();
  }, [hasMore, loading, fetchPage]);

  const formatDuration = (sec: number) => {
    const m = Math.floor(sec / 60);
    const s = sec % 60;
    return `${m}:${s.toString().padStart(2, "0")}`;
  };

  const formatViews = (n: number) => {
    if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M views`;
    if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K views`;
    return `${n} views`;
  };

  return (
    <div className="video-grid">
      {videos.map((v) => (
        <a key={v.id} href={`/watch/${v.slug}`} className="video-card">
          <div className="thumbnail">
            <img loading="lazy" src={v.thumbnail_url} alt={v.title} />
            <span className="duration">{formatDuration(v.duration_seconds)}</span>
          </div>
          <div className="video-info">
            <h3>{v.title}</h3>
            <p className="channel">{v.channel_name}</p>
            <p className="meta">{formatViews(v.view_count)}</p>
          </div>
        </a>
      ))}
      {hasMore && <div ref={observerRef} className="loading-sentinel" />}
      {loading && <p>Loading more videos...</p>}
    </div>
  );
}

server {
    listen 80;
    server_name video.example.com;

    # HLS segment serving with aggressive caching
    location /hls/ {
        alias /data/hls/;
        add_header Access-Control-Allow-Origin *;
        add_header Cache-Control "public, max-age=31536000, immutable";

        types {
            application/vnd.apple.mpegurl m3u8;
            video/mp2t ts;
        }

        # Enable sendfile for zero-copy serving
        sendfile on;
        tcp_nopush on;
        tcp_nodelay on;
    }

    # Thumbnail serving
    location /thumbnails/ {
        alias /data/thumbnails/;
        add_header Cache-Control "public, max-age=86400";
        expires 1d;
    }

    # Proxy API requests to Flask
    location /api/ {
        proxy_pass http://127.0.0.1:5000/;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        client_max_body_size 50M;  # For chunk uploads
    }
}
